def _interpolate(self, value, line_num, filename):
    """Replace ${var} references with variable values."""
    def replacer(match):
        var_name = match.group(1)
        if var_name in self.variables:
            return self.variables[var_name]
        if self.strict:
            raise ParseError(
                f"Undefined variable '${{{var_name}}}'",
                line_num, filename
            )
        # Non-strict: silently replace undefined variables with empty string
        return ""

    return re.sub(r'\$\{(\w+)\}', replacer, value)

def get_undefined_references(self, text):
    """Return all variable names referenced in text but not currently defined.

    Does not raise an error; always returns a list.
    """
    seen = set()
    result = []
    for var_name in re.findall(r'\$\{(\w+)\}', text):
        if var_name not in self.variables and var_name not in seen:
            seen.add(var_name)
            result.append(var_name)
    return result
